class Solution:
    def maxIncreaseKeepingSkyline(self, grid):
        n = len(grid)
        total = 0
        for r in range(n):
            for c in range(n):
                rowmax = max(grid[r][j] for j in range(n))
                colmax = max(grid[i][c] for i in range(n))
                total += min(rowmax, colmax) - grid[r][c]
        return total

