class Solution:
    def maxIncreaseKeepingSkyline(self, grid):
        n = len(grid)
        rowmax = [max(row) for row in grid]
        colmax = [max(grid[i][c] for i in range(n)) for c in range(n)]
        total = 0
        for r in range(n):
            for c in range(n):
                total += min(rowmax[r], colmax[c]) - grid[r][c]
        return total

