var maxIncreaseKeepingSkyline = function(grid) {
    const n = grid.length;
    const rowmax = grid.map(row => Math.max(...row));
    const colmax = [];
    for (let c = 0; c < n; c++) {
        let m = 0;
        for (let r = 0; r < n; r++) m = Math.max(m, grid[r][c]);
        colmax.push(m);
    }
    let total = 0;
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < n; c++) {
            total += Math.min(rowmax[r], colmax[c]) - grid[r][c];
        }
    }
    return total;
};
